queries.sparql:
PREFIX : <http://ambrosia.example.org/healthcare#>
PREFIX p: <http://ambrosia.example.org/healthcare/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?coursename ?duration WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCourses ?child ; p:hasMedical_Schools ?parent . } GROUP BY ?child }
  ?child p:courseName ?coursename .
  ?child p:duration ?duration .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Medical_Schools } }
  FILTER(?nf = ?total)
}

